int n;
int dfs(int x,int z){
    if(z>n){
        return 0;
    }else{
        if(x==10&&z==n){
            return 1;
        }else if(x==10){
            return 0;
        }else{
            int ans=0;
            for(int i=1;i<=3;i++) ans+=dfs(x+1,z+i);
            return ans;
        }
    }
}
